// Parse the Telegram message — user sends the content topic
const msg = $input.first().json.message;
const topic = (msg.text || '').trim().substring(0, 200);
const chatId = msg.chat.id;

if (!topic) {
  throw new Error('No topic received — send me a topic to write about');
}

return [{
  json: {
    topic,
    chatId,
    iterationCount: 0,
    criticFeedback: '',
    startTime: new Date().toISOString()
  }
}];

