// Prepare data for the Writer Agent
// Handles BOTH first pass (from Research Agent) AND loop rewrites (from Inject Feedback)

let topic, chatId, iterationCount, criticFeedback, keyPoints, context, angle;

if ($json.output) {
  // --- FIRST PASS: input is Research Agent plain text output ---
  const research = $json.output;
  const parseData = $('Parse Input').first().json;

  keyPoints = [research];
  context = research;
  angle = '';
  topic = parseData.topic;
  chatId = parseData.chatId;
  iterationCount = parseData.iterationCount;
  criticFeedback = parseData.criticFeedback || '';
} else {
  // --- LOOP REWRITE: input is Inject Feedback output ---
  keyPoints = $json.keyPoints || [];
  context = $json.context || '';
  angle = $json.angle || '';
  topic = $json.topic;
  chatId = $json.chatId;
  iterationCount = $json.iterationCount;
  criticFeedback = $json.criticFeedback || '';
}

const keyPointsText = Array.isArray(keyPoints)
  ? keyPoints.map((p, i) => `${i + 1}. ${p}`).join('\n')
  : keyPoints;

const feedbackSection = criticFeedback
  ? `\n\nCRITIC FEEDBACK — address these points in your rewrite:\n${criticFeedback}`
  : '';

const writerPrompt = `Topic: ${topic}\n\nAngle to use: ${angle}\n\nContext: ${context}\n\nKey facts to weave in:\n${keyPointsText}${feedbackSection}`;

return [{
  json: {
    topic,
    chatId,
    iterationCount,
    criticFeedback,
    keyPoints,
    context,
    angle,
    writerPrompt
  }
}];

// Extract Writer Agent output and carry all data forward for the Critic Agent

const draft = $json.output;
const prevData = $('Prepare Writer Prompt').item.json;

if (!draft) {
  throw new Error('Writer Agent returned no draft');
}

return [{
  json: {
    topic: prevData.topic,
    chatId: prevData.chatId,
    iterationCount: prevData.iterationCount,
    keyPoints: prevData.keyPoints,
    context: prevData.context,
    angle: prevData.angle,
    criticFeedback: prevData.criticFeedback,
    draft,
    wordCount: draft.split(' ').length
  }
}];

// Extract Critic Agent output

const criticOutput = $json.output || '';
const prevData = $('Prepare Critic Prompt').item.json;

// Parse score from text output
const scoreMatch = criticOutput.match(/\b([0-9]|10)\s*\/\s*10|\bscore[:\s]+([0-9]|10)\b/i);
const score = scoreMatch ? parseInt(scoreMatch[1] || scoreMatch[2]) : 7;
const passed = score >= 7;
const feedback = criticOutput;

return [{
  json: {
    topic: prevData.topic,
    chatId: prevData.chatId,
    iterationCount: prevData.iterationCount,
    keyPoints: prevData.keyPoints,
    context: prevData.context,
    angle: prevData.angle,
    draft: prevData.draft,
    wordCount: prevData.wordCount,
    score,
    passed,
    feedback
  }
}];

// Draft didn't pass auto-review — inject critic feedback and loop back to writer

const improvementText = ($json.feedback || '').trim();

return [{
  json: {
    topic: $json.topic,
    chatId: $json.chatId,
    iterationCount: $json.iterationCount + 1,
    keyPoints: $json.keyPoints,
    context: $json.context,
    angle: $json.angle,
    criticFeedback: improvementText,
    draft: $json.draft
  }
}];

// Build approval message data

const resumeUrl = $execution.resumeUrl;
const approveUrl = resumeUrl + '?action=approve';
const rejectUrl = resumeUrl + '?action=reject';

const iterationNote = $json.iterationCount > 0
  ? `📝 Rewrite #${$json.iterationCount} — Critic score: ${$json.score}/10`
  : `🎯 Critic score: ${$json.score}/10`;

const approvalMessage = `${iterationNote}\nWords: ${$json.wordCount}\n\nTap below to approve or reject.`;

return [{
  json: {
    approvalMessage,
    approveUrl,
    rejectUrl,
    topic: $json.topic,
    chatId: $json.chatId,
    draft: $json.draft,
    score: $json.score,
    feedback: $json.feedback,
    wordCount: $json.wordCount,
    iterationCount: $json.iterationCount,
    keyPoints: $json.keyPoints,
    context: $json.context,
    angle: $json.angle
  }
}];

// Inject rejection feedback and loop back to Writer Agent

const prevData = $('Format Approval Message').item.json;

return [{
  json: {
    topic: prevData.topic,
    chatId: prevData.chatId,
    iterationCount: prevData.iterationCount + 1,
    keyPoints: prevData.keyPoints,
    context: prevData.context,
    angle: prevData.angle,
    criticFeedback: prevData.feedback + '\n\nNote: The human reviewer also rejected this draft. Significantly improve it.',
    draft: prevData.draft
  }
}];

